exercises.code:
-- Advisor access pattern: get advisor + clients
CREATE INDEX idx_advisor ON advisory_entities ae (
    ae.data.advisorId.number()
);

-- Account access pattern: get holdings + transactions
CREATE INDEX idx_account ON advisory_entities ae (
    ae.data.accountId.number()
);

-- Symbol access pattern: find holdings across all accounts
CREATE INDEX idx_symbol ON advisory_entities ae (
    ae.data.symbol.string()
);

-- Use the symbol index to find all AAPL holdings across accounts
SELECT ae.data.accountId.number() AS account_id,
       ae.data.quantity.number() AS quantity,
       ae.data.marketValue.number() AS market_value
FROM advisory_entities ae
WHERE ae.data.symbol.string() = 'AAPL'
  AND ae.data.entityType.string() = 'holding';

