CREATE INDEX idx_advisor ON advisory_entities ae (
    ae.data.advisorId.number()
);

CREATE INDEX idx_account ON advisory_entities ae (
    ae.data.accountId.number()
);

CREATE INDEX idx_symbol ON advisory_entities ae (
    ae.data.symbol.string()
);

CREATE MULTIVALUE INDEX idx_holding_tags ON advisory_entities ae
    (JSON_TABLE(ae.data, '$'
        COLUMNS (
            entity_type VARCHAR2(50) PATH '$.entityType'
                ERROR ON ERROR NULL ON EMPTY NULL ON MISMATCH,
            NESTED PATH '$.tags[*]' COLUMNS (tag VARCHAR2(50) PATH '$'
                ERROR ON ERROR NULL ON EMPTY NULL ON MISMATCH)
        )
    ));
